```js
// ES Module（瀏覽器 + 現代 Node）
// math.js
export function add(a, b) { return a + b; }
export const PI = 3.14;
export default class Calculator {}

// main.js
import Calc, { add, PI } from "./math.js";
import * as math from "./math.js";
import "./side-effect.js"; // 只執行不取值

// 動態 import（lazy load）
