```js
// 兩種建立方式
const r1 = /hello/i;
const r2 = new RegExp("hello", "i");

// 旗標
// g - 全局（找所有）
// i - 忽略大小寫
// m - 多行
// s - dotAll（. 可以匹配換行）
// u - Unicode
// y - sticky
// d - 帶 indices

// 常用方法
"hello".match(/l+/g);            // ['ll']
"hello".replace(/l/g, "L");       // "heLLo"
"a,b,c".split(/,/);              // ['a','b','c']
/^\d+$/.test("123");              // true
"hello".matchAll(/l/g);          // iterator
```


